describe('notification ordering', () => {
  it('should deliver notifications in the order they were emitted', async () => {
    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events in sequence — order:created first, then status change
    await eventBus.emit(orderCreatedEvent);
    await eventBus.emit(statusChangedEvent);

    // Verify adapter received deliveries in the correct order
    const sentEmails = emailAdapter.getSentEmails();
    expect(sentEmails).toHaveLength(2);
    expect(sentEmails[0]?.subject).toContain('Order Confirmation');
    expect(sentEmails[1]?.subject).toContain('Order Update');

    // Verify persisted notifications are also in order
    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    expect(notifications[0]?.notificationType).toBe('order_confirmation');
    expect(notifications[1]?.notificationType).toBe('order_status_update');
  });
});

